#include <iostream>
using namespace std;

// Structure for linked list node
struct Node {
    int data;
    Node* next;
    Node(int data) {
        this->data = data;
        this->next = nullptr;
    }
};

// Function to print the linked list
void printList(Node* head) {
    Node* temp = head;
    while (temp != nullptr) {
        if (temp->next != nullptr) {
            cout << temp->data << " ";
        } else {
            cout << temp->data;
        }
        temp = temp->next;
    }
    cout << endl;
}

// Iterative method to reverse the linked list
Node* reverseIterative(Node* head) {
    Node* prev = nullptr;
    Node* current = head;
    Node* next = nullptr;

    while (current != nullptr) {
        next = current->next;  // Store next node
        current->next = prev;  // Reverse the current node's pointer
        prev = current;        // Move prev and current one step forward
        current = next;
    }

    return prev;  // prev is the new head of the reversed list
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int n;
    cin >> n;
    Node* head = nullptr;
    Node* temp = nullptr;

    for (int i = 0; i < n; i++) {
        int data;
        cin >> data;

        Node* newNode = new Node(data);

        if (head == nullptr) {
            head = newNode;  // First node becomes the head
        } else {
            temp->next = newNode;  // Link the new node to the previous one
        }
        temp = newNode;  // Move temp to the new node
    }

    // Reversing the list iteratively
    head = reverseIterative(head);
    printList(head);
    return 0;
}

